// Five charts (chart..chart4) + a live data table, all over the 'trades' set.
var cf = ApexCharts.getCrossfilter('trades')
var readout = document.getElementById('cfd-readout')

if (cf) {
  // Bind the data table to the filtered rows; it re-renders on every change.
  cf.dataTable(document.getElementById('cfd-table'), {
    columns: [
      { field: 'id', label: '#' },
      { field: 'quarter', label: 'Quarter' },
      { field: 'day', label: 'Day' },
      { field: 'outcome', label: 'Outcome' },
      {
        field: 'pct',
        label: 'Fluctuation %',
        format: function (v) {
          return v.toFixed(2) + '%'
        },
      },
      { field: 'volume', label: 'Volume' },
    ],
  })

  cf.on('change', function (state) {
    var ids = Object.keys(state.filters)
    var label = ids.length ? ids.join(', ') : 'none'
    readout.textContent =
      state.filteredCount +
      ' / ' +
      state.total +
      ' trades   (active: ' +
      label +
      ')'
  })

  // Seed the readout with the unfiltered totals.
  var s = cf.state()
  readout.textContent =
    s.filteredCount + ' / ' + s.total + ' trades   (active: none)'
}

document.getElementById('cfd-reset').addEventListener('click', function () {
  if (cf) cf.reset()
})

.cfd {
  max-width: 700px;
  margin: 10px auto;
  font-family: Helvetica, Arial, sans-serif;
  color: #1f2430;
}
.cfd-bar {
  display: flex;
  gap: 12px;
  align-items: center;
  flex-wrap: wrap;
  margin: 4px 6px 12px;
}
.cfd-bar button {
  padding: 6px 13px;
  cursor: pointer;
  border: 1px solid #6366f1;
  color: #4338ca;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
}
.cfd-bar .readout {
  font-family: monospace;
  font-size: 13px;
  color: #445;
}
.cfd-grid {
  display: grid;
  /* Auto-fit reflows the three categorical charts from 3 columns down to 2,
       then 1, as the container narrows, so they never get crushed at ~700px. */
  grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
  gap: 8px;
}
.cfd-card {
  border: 1px solid #eef;
  border-radius: 8px;
  padding: 6px;
}
/* The two brush histograms always take a full row, whatever the column count. */
.cfd-card.brush {
  grid-column: 1 / -1;
}
.cfd-tablewrap {
  margin: 12px 6px;
  max-height: 280px;
  overflow: auto;
  border: 1px solid #eef;
  border-radius: 8px;
}
.cfd-note {
  background: #eef2ff;
  border-left: 3px solid #6366f1;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
  margin: 12px 6px;
}
.cfd-note code {
  background: #dfe3ff;
  padding: 1px 5px;
  border-radius: 3px;
}
